from pydantic import BaseModel, Field
from typing import Optional

class InvoiceData(BaseModel):
    invoice_number: str = Field(..., description="Unique invoice ID")
    date: str = Field(..., description="Invoice date in YYYY-MM-DD")
    total_amount: float = Field(..., description="Total invoice amount")
    vendor_name: str = Field(..., description="Vendor/Supplier name")
    line_items: list[dict] = Field(default_factory=list)

    class Config:
        json_schema_extra = {"required": ["invoice_number", "date", "total_amount"]}

final_message = groupchat.messages[-1]['content']
try:
    extracted_data = InvoiceData.model_validate_json(final_message)
    print(f"✅ Valid extraction: {extracted_data}")
except ValidationError as e:
    print(f"❌ Schema violation: {e}")
